import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

export default function Dashboard() {
  const [incidents, setIncidents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [filter, setFilter] = useState("ALL");

  const fetchData = async () => {
    try {
      setLoading(true);
      const res = await fetch("http://localhost:8000/incidents");
      const data = await res.json();
      setIncidents(data);
      setError("");
    } catch (err) {
      setError("Failed to fetch incidents");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  // 🔎 Filtering
  const filtered = incidents.filter((i) => {
    if (filter === "ALL") return true;
    return i.status === filter;
  });

  // 🔽 Sorting (latest first)
  const sorted = [...filtered].sort((a, b) => b.id - a.id);

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      
      <h1 style={{ textAlign: "center" }}>🚨 Incident Dashboard</h1>

      {/* FILTER */}
      <div style={{ marginBottom: "15px", textAlign: "center" }}>
        <button onClick={() => setFilter("ALL")}>All</button>
        <button onClick={() => setFilter("OPEN")} style={{ marginLeft: "10px" }}>Open</button>
        <button onClick={() => setFilter("CLOSED")} style={{ marginLeft: "10px" }}>Closed</button>
      </div>

      {/* LOADING */}
      {loading && <p style={{ textAlign: "center" }}>Loading...</p>}

      {/* ERROR */}
      {error && <p style={{ color: "red", textAlign: "center" }}>{error}</p>}

      {/* DATA */}
      {!loading && sorted.length === 0 && (
        <p style={{ textAlign: "center" }}>No incidents found</p>
      )}

      <div style={{ display: "flex", flexWrap: "wrap", gap: "15px" }}>
        {sorted.map((i) => (
          <div
            key={i.id}
            style={{
  flex: "1 1 300px",
  borderRadius: "12px",
  padding: "20px",
  background: "#ffffff",
  boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
  transition: "0.2s",
  borderLeft: i.status === "OPEN" ? "6px solid #ff4d4f" : "6px solid #28a745"
}}
onMouseEnter={(e) => (e.currentTarget.style.transform = "scale(1.02)")}
onMouseLeave={(e) => (e.currentTarget.style.transform = "scale(1)")}
          >
            <h3>Incident #{i.id}</h3>

            <p><b>Component:</b> {i.component_id}</p>
            <p><b>Severity:</b> {i.severity}</p>

            <p>
              <b>Status:</b>{" "}
              <span style={{ color: i.status === "OPEN" ? "red" : "green" }}>
                {i.status}
              </span>
            </p>

            <p><b>Signals:</b> {i.signal_count}</p>

            <p>
              <b>Start:</b>{" "}
              {new Date(i.start_time).toLocaleString()}
            </p>

            <Link to={`/incident/${i.id}`}>
              <button style={{ marginTop: "10px" }}>View Details</button>
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
}
